"use client";

import React, { createContext, useContext, useState, useEffect } from "react";
import { ResumeData } from "@/types/resume";
import { initialResumeData } from "@/constants/initialData";

interface ResumeContextType {
  data: ResumeData;
  setData: React.Dispatch<React.SetStateAction<ResumeData>>;
  template: "modern" | "classic";
  setTemplate: React.Dispatch<React.SetStateAction<"modern" | "classic">>;
}

const ResumeContext = createContext<ResumeContextType | undefined>(undefined);

export function ResumeProvider({ children }: { children: React.ReactNode }) {
  const [data, setData] = useState<ResumeData>(initialResumeData);
  const [template, setTemplate] = useState<"modern" | "classic">("modern");

  // Load from localStorage on mount
  useEffect(() => {
    const savedData = localStorage.getItem("resume-builder-data");
    const savedTemplate = localStorage.getItem("resume-builder-template");

    if (savedData) {
      try {
        setData(JSON.parse(savedData));
      } catch (e) {
        console.error("Failed to parse saved resume data");
      }
    }

    if (savedTemplate) {
      setTemplate(savedTemplate as "modern" | "classic");
    }
  }, []);

  // Save to localStorage on change
  useEffect(() => {
    localStorage.setItem("resume-builder-data", JSON.stringify(data));
    localStorage.setItem("resume-builder-template", template);
  }, [data, template]);

  return (
    <ResumeContext.Provider value={{ data, setData, template, setTemplate }}>
      {children}
    </ResumeContext.Provider>
  );
}

export function useResume() {
  const context = useContext(ResumeContext);
  if (context === undefined) {
    throw new Error("useResume must be used within a ResumeProvider");
  }
  return context;
}

import { GoogleGenerativeAI } from "@google/generative-ai";

const genAI = new GoogleGenerativeAI(process.env.NEXT_PUBLIC_GEMINI_API_KEY!);

export async function generateResumeContent(prompt: string) {
  try {
    const model = genAI.getGenerativeModel({ model: "gemini-1.5-flash" });
    const result = await model.generateContent(prompt);
    const response = await result.response;
    const text = response.text();
    return text;
  } catch (error: any) {
    console.error("Gemini API Error:", error.message);
    throw new Error("Failed to generate content. Please check your API key.");
  }
}

export async function refineContent(section: string, userInput: string) {
  try {
    const response = await fetch("/api/ai/generate", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({ section, userInput }),
    });

    if (!response.ok) {
      const errorData = await response.json();
      throw new Error(errorData.error || "Failed to refine content");
    }

    const data = await response.json();
    return data.content;
  } catch (error: any) {
    console.error("AI Service Error:", error.message);
    throw error;
  }
}

import { createClient } from '@supabase/supabase-js';

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!;

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

export async function saveResume(user_id: string, resume_data: any, template: string) {
  const { data, error } = await supabase
    .from('resumes')
    .upsert({
      user_id,
      resume_data,
      template,
      updated_at: new Date().toISOString(),
    })
    .select()
    .single();

  if (error) throw error;
  return data;
}

export async function fetchResumes(user_id: string) {
  const { data, error } = await supabase
    .from('resumes')
    .select('*')
    .eq('user_id', user_id)
    .order('updated_at', { ascending: false });

  if (error) throw error;
  return data;
}
